// PARAMETRI
float density = 10.0;

// [FIX] Usa i colori del pannello laterale
vec3 c1 = vec3(1.0, 0.0, 0.0); // Rosso
vec3 c2 = vec3(1.0, 1.0, 0.0); // Giallo

float freq = density * 0.05;

// Coordinate scalate
// Moltiplichiamo per 25.0 invece di 512*0.05 per semplicità
float xx = u * 25.0; 
float yy = v * 25.0;

// --- FORMULA PLASMA ---
float v1 = sin(xx + yy);
float v2 = sin((xx * sin(yy/2.0)) + (yy * cos(xx/3.0)));

float cx = xx + 0.5 * sin(yy/5.0);
float cy = yy + 0.5 * cos(xx/3.0);
float v3 = sin(sqrt(100.0 * (cx*cx + cy*cy) + 1.0));

float vf = (v1 + v2 + v3) / 3.0;

// [FIX] Rinominato 't' in 'plasmaVal' per evitare conflitti
float plasmaVal = vf * 0.5 + 0.5;

return mix(c1, c2, plasmaVal);

